      profileImageUrl: z.string().url("URL de imagen inv\xE1lida").optional().or(z.literal("")).nullable(),
      publicPhone: z.string().optional().nullable(),
      publicEmail: z.string().email("Email inv\xE1lido").optional().or(z.literal("")).nullable(),
