    equiposCriticos = pgTable("equipos_criticos", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      codigo: varchar("codigo", { length: 50 }).unique(),
      // Código único del equipo (auto-generated if not provided)
      nombre: varchar("nombre", { length: 255 }).notNull(),
      area: varchar("area").notNull(),
      // administracion, produccion, laboratorio, bodega_materias_primas, bodega_productos_terminados
      criticidad: varchar("criticidad").notNull().default("media"),
      // baja, media, alta, critica
      ubicacion: text("ubicacion"),
      // Ubicación específica del equipo
      descripcion: text("descripcion"),
      // Descripción del equipo
      // Jerarquía de equipos (equipo padre para componentes)
      equipoPadreId: varchar("equipo_padre_id"),
      // Referencia al equipo padre si es un componente
      // Información técnica
      fabricante: varchar("fabricante", { length: 100 }),
      modelo: varchar("modelo", { length: 100 }),
      numeroSerie: varchar("numero_serie", { length: 100 }),
      fechaInstalacion: date("fecha_instalacion"),
      potencia: varchar("potencia", { length: 50 }),
      // ej: "5.5 HP", "220V 3-phase"
      // Plan preventivo
      frecuenciaPreventivo: varchar("frecuencia_preventivo"),
      // semanal, mensual, trimestral, semestral, anual
      ultimoMantPreventivo: timestamp("ultimo_mant_preventivo"),
      proximoMantPreventivo: timestamp("proximo_mant_preventivo"),
      // Información adicional
      repuestosCriticos: text("repuestos_criticos"),
      // Lista de repuestos críticos
      arbolFallas: text("arbol_fallas"),
      // Árbol simple de fallas (texto)
      manualesUrl: text("manuales_url"),
      // URLs de manuales/PDFs separados por comas
      notas: text("notas"),
      // Estado
      estadoActual: varchar("estado_actual").default("operativo"),
      // operativo, en_mantencion, detenido, fuera_de_servicio
      // Metadata
      createdAt: timestamp("created_at").defaultNow(),
      updatedAt: timestamp("updated_at").defaultNow()
    }, (table) => ({
      codigoIdx: index("IDX_equipos_codigo").on(table.codigo),
      areaIdx: index("IDX_equipos_area").on(table.area),
      criticidadIdx: index("IDX_equipos_criticidad").on(table.criticidad)
    }));
