      // gran_mantenimiento, overhaul, rectificacion, reemplazo, mejora
      costoEstimado: numeric("costo_estimado", { precision: 15, scale: 2 }).notNull(),
      mes: integer("mes").notNull(),
      // 1-12
      anio: integer("anio").notNull(),
      area: varchar("area"),
      // NULL para global, o área específica
      estado: varchar("estado").default("planificado").notNull(),
      // planificado, aprobado, en_ejecucion, completado, cancelado
      prioridad: varchar("prioridad").default("media"),
      // baja, media, alta
      notas: text("notas"),
      // Vinculación a OT real cuando se ejecute
      otGeneradaId: varchar("ot_generada_id"),
      // FK a solicitudes_mantencion cuando se crea la OT
      creadoPorId: varchar("creado_por_id").notNull(),
      creadoPorName: varchar("creado_por_name"),
