  /**
   * Extracts the parent product name by stripping format and color suffixes.
   * E.g. "ESMALTE AL AGUA COPPER BLANCO GALON" → "ESMALTE AL AGUA COPPER"
   */
  extractParentProductName(fullName) {
    if (!fullName) return fullName;
    let name = fullName.trim();
    const formatPatterns = [
      /\s+4\s*GALONES?\s*$/i,
      /\s+1\/4\s*(GALON|GALÓN)?\s*$/i,
      /\s+1\/4\s*$/i,
      /\s+(GALON|GALÓN)\s*$/i,
      /\s+GL\s*$/i,
      /\s+GAL\s*$/i,
      /\s+BALDE?\s*$/i,
      /\s+BLD\s*$/i,
      /\s+BD\s*$/i,
      /\s+TINETA\s*$/i,
      /\s+KILO\s*$/i,
      /\s+KG\s*$/i,
      /\s+LITROS?\s*$/i,
      /\s+LTS?\s*$/i,
      /\s+ONZAS?\s*$/i,
      /\s+OZ\s*$/i,
      /\s+METROS?\s*$/i,
      /\s+MTS?\s*$/i,
      /\s+CUARTO\s*$/i
    ];
    const colorPatterns = [
      /\s+BLANCO\s*$/i,
      /\s+NEGRO\s*$/i,
      /\s+ROJO\s*$/i,
      /\s+AZUL\s+PACIFICO\s*$/i,
      /\s+AZUL\s*$/i,
      /\s+VERDE\s*$/i,
      /\s+AMARILLO\s*$/i,
      /\s+GRIS\s*$/i,
      /\s+CAFE\s*$/i,
      /\s+CAFÉ\s*$/i,
      /\s+MARRON\s*$/i,
      /\s+MARRÓN\s*$/i,
      /\s+ROSA\s*$/i,
      /\s+ROSADO\s*$/i,
      /\s+NARANJA\s*$/i,
      /\s+ANARANJADO\s*$/i,
      /\s+VIOLETA\s*$/i,
      /\s+MORADO\s*$/i,
      /\s+INCOLORO\s*$/i,
      /\s+TRANSPARENTE\s*$/i,
      /\s+BEIGE\s*$/i,
      /\s+CREMA\s*$/i,
      /\s+MARFIL\s*$/i,
      /\s+CELESTE\s*$/i
    ];
    for (let pass = 0; pass < 3; pass++) {
      for (const pattern of formatPatterns) {
        name = name.replace(pattern, "");
      }
      for (const pattern of colorPatterns) {
        name = name.replace(pattern, "");
      }
    }
    return name.trim();
  }
