  async initializePublicCatalogs() {
    console.log("\u{1F527} Inicializando cat\xE1logos p\xFAblicos para todos los vendedores...");
    const salespeople = await db.select().from(salespeopleUsers);
    let updated = 0;
    let skipped = 0;
    for (const salesperson of salespeople) {
      if (salesperson.publicSlug && salesperson.catalogEnabled) {
        skipped++;
        continue;
      }
      const generateSlug = (name) => {
        return name.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9\s-]/g, "").replace(/\s+/g, "-").replace(/-+/g, "-").trim().replace(/^-|-$/g, "");
      };
      let baseSlug = generateSlug(salesperson.salespersonName);
      if (!baseSlug) {
        baseSlug = `vendedor-${salesperson.id.substring(0, 8)}`;
      }
      let slug = baseSlug;
      let counter = 1;
      const existingSlugs = await db.select({ slug: salespeopleUsers.publicSlug }).from(salespeopleUsers).where(sql3`${salespeopleUsers.publicSlug} LIKE ${baseSlug + "%"}`);
      const slugSet = new Set(existingSlugs.map((s) => s.slug).filter(Boolean));
      while (slugSet.has(slug)) {
        slug = `${baseSlug}-${counter}`;
        counter++;
      }
      await db.update(salespeopleUsers).set({
        publicSlug: slug,
        catalogEnabled: true,
        updatedAt: /* @__PURE__ */ new Date()
      }).where(eq2(salespeopleUsers.id, salesperson.id));
      console.log(`  \u2705 Cat\xE1logo activado: ${salesperson.salespersonName} \u2192 /catalogo/${slug}`);
      updated++;
    }
    console.log(`\u2705 Cat\xE1logos inicializados: ${updated} actualizados, ${skipped} ya configurados`);
    return { updated, skipped };
  }
