  // Quote to Order conversion
  async convertQuoteToOrder(quoteId, userId) {
    const quote = await this.getQuoteById(quoteId);
    if (!quote) {
      throw new Error("Quote not found");
    }
    const items = await this.getQuoteItems(quoteId);
    const order = await this.createOrder({
      clientName: quote.clientName,
      clientId: quote.clientId,
      orderNumber: `ORD-${Date.now()}`,
      // Generate order number
      createdBy: userId,
      status: "draft",
      priority: "medium",
      notes: `Converted from quote ${quote.quoteNumber}. Original notes: ${quote.notes || "N/A"}`,
      totalAmount: quote.total
    });
    for (const item of items) {
      await this.createOrderItem({
        orderId: order.id,
        productName: item.productName,
        productCode: item.productCode,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        totalPrice: item.totalPrice,
        notes: item.notes
      });
    }
    await this.updateQuote(quoteId, { status: "converted" });
    return order;
  }
  // Quote duplication for editing (atomic operation)
  async duplicateQuote(originalQuoteId, userId) {
    const newQuote = await db.transaction(async (tx) => {
      const [originalQuote] = await tx.select().from(quotes).where(eq2(quotes.id, originalQuoteId));
      if (!originalQuote) {
        throw new Error("Quote not found");
      }
      const originalItems = await tx.select().from(quoteItems).where(eq2(quoteItems.quoteId, originalQuoteId));
      const quoteNumber = `Q-${Date.now()}`;
      const [newQuote2] = await tx.insert(quotes).values({
        clientName: originalQuote.clientName,
        clientRut: originalQuote.clientRut,
        clientEmail: originalQuote.clientEmail,
        clientPhone: originalQuote.clientPhone,
        clientAddress: originalQuote.clientAddress,
        validUntil: originalQuote.validUntil,
        notes: originalQuote.notes ? `Copia de cotizaci\xF3n #${originalQuote.quoteNumber} - ${originalQuote.notes}` : `Copia de cotizaci\xF3n #${originalQuote.quoteNumber}`,
        subtotal: originalQuote.subtotal,
        total: originalQuote.total,
        taxAmount: originalQuote.taxAmount,
        discount: originalQuote.discount,
        taxRate: originalQuote.taxRate,
        status: "draft",
        // Always create as draft
        createdBy: userId,
        quoteNumber
      }).returning();
      if (originalItems.length > 0) {
        const newItemsData = originalItems.map((item) => ({
          quoteId: newQuote2.id,
          type: item.type,
          productName: item.productName,
          productCode: item.productCode,
          customSku: item.customSku,
          quantity: item.quantity,
          unitPrice: item.unitPrice,
          totalPrice: item.totalPrice,
          notes: item.notes
        }));
        await tx.insert(quoteItems).values(newItemsData);
      }
      return { newQuote: newQuote2, hasItems: originalItems.length > 0 };
    });
    return newQuote.newQuote;
  }
