  // TINTOMETRÍA CALCULATION METHODS
  async calculateColorCost(colorId, envaseId) {
    try {
      const [color] = await db.select().from(colores).where(eq2(colores.colorId, colorId));
      if (!color) return null;
      const [envase] = await db.select().from(envases).where(eq2(envases.envaseId, envaseId));
      if (!envase) return null;
      const [base] = await db.select().from(bases).where(eq2(bases.baseId, color.baseId));
      if (!base) return null;
      const recetasColor = await db.select({
        pigmentoCode: recetas.pigmentoCode,
        fraccionPeso: recetas.fraccionPeso,
        pigmentoCosto: pigments.costoKgClp
      }).from(recetas).leftJoin(pigments, eq2(recetas.pigmentoCode, pigments.pigmentoCode)).where(eq2(recetas.colorId, colorId));
      const paintWeightKg = Number(envase.kgPorEnvase);
      const totalFraccionPigmentos = recetasColor.reduce((sum3, receta) => sum3 + Number(receta.fraccionPeso), 0);
      const fraccionBase = Math.max(0, 1 - totalFraccionPigmentos);
      const baseCost = fraccionBase * paintWeightKg * Number(base.costoKgClp);
      const pigmentsCost = recetasColor.reduce((sum3, receta) => {
        const pigmentWeight = Number(receta.fraccionPeso) * paintWeightKg;
        const pigmentCost = pigmentWeight * Number(receta.pigmentoCosto || 0);
        return sum3 + pigmentCost;
      }, 0);
      const totalPaintCost = baseCost + pigmentsCost;
      const totalCost = totalPaintCost + Number(envase.costoEnvaseClp);
      const [priceMultiplierParam] = await db.select().from(parametros).where(eq2(parametros.parametro, "precio_multiplicador"));
      const suggestedPrice = priceMultiplierParam ? totalCost * Number(priceMultiplierParam.valor) : void 0;
      return {
        colorId,
        envaseId,
        baseId: color.baseId,
        baseCost,
        pigmentsCost,
        envaseData: envase,
        totalPaintCost,
        totalCost,
        suggestedPrice
      };
    } catch (error) {
      console.error("Error calculating color cost:", error);
      throw error;
    }
  }
