  // Validación técnica
  async validarReclamoTecnico(id, procede, areaResponsable, notas, userId, userName) {
    const reclamo = await this.getReclamoGeneralById(id);
    if (!reclamo) {
      throw new Error("Reclamo not found");
    }
    let nuevoEstado;
    if (procede) {
      if (areaResponsable === "laboratorio") {
        nuevoEstado = "en_laboratorio";
      } else if (areaResponsable === "produccion") {
        nuevoEstado = "en_produccion";
      } else {
        nuevoEstado = "en_area_responsable";
      }
    } else {
      nuevoEstado = "en_revision_tecnica";
    }
    let responsableArea = null;
    if (procede && areaResponsable) {
      const usuariosArea = await db.select().from(users).where(
        or2(
          eq2(users.role, areaResponsable),
          eq2(users.role, `area_${areaResponsable}`)
        )
      ).limit(1);
      if (usuariosArea.length > 0) {
        responsableArea = usuariosArea[0];
      }
    }
    const [updated] = await db.update(reclamosGenerales).set({
      procede,
      areaResponsableActual: procede ? areaResponsable : reclamo.areaResponsableActual,
      estado: nuevoEstado,
      updatedAt: /* @__PURE__ */ new Date(),
      informeTecnico: notas || null,
      responsableAreaId: responsableArea ? responsableArea.id : null,
      responsableAreaName: responsableArea ? responsableArea.fullName : null
    }).where(eq2(reclamosGenerales.id, id)).returning();
    const notasHistorial = notas || (procede ? `Reclamo validado y derivado a ${areaResponsable}${responsableArea ? ` - Asignado a ${responsableArea.fullName}` : ""}` : "Reclamo marcado como no procedente - pendiente revisi\xF3n");
    await this.createReclamoGeneralHistorial({
      reclamoId: id,
      estadoAnterior: reclamo.estado,
      estadoNuevo: nuevoEstado,
      userId,
      userName,
      notas: notasHistorial
    });
    if (procede && responsableArea) {
      await this.createNotification({
        userId: responsableArea.id,
        type: "reclamo_asignado",
        title: "Reclamo Asignado",
        message: `Se te asign\xF3 el reclamo del cliente "${updated.clientName}" del \xE1rea ${areaResponsable}`,
        relatedReclamoId: updated.id,
        read: false
      });
    }
    return updated;
  }
