  async createSolicitudMantencion(solicitud) {
    const [newSolicitud] = await db.insert(solicitudesMantencion).values(solicitud).returning();
    await this.createMantencionHistorial({
      mantencionId: newSolicitud.id,
      estadoAnterior: null,
      estadoNuevo: "pendiente",
      userId: newSolicitud.solicitanteId,
      userName: newSolicitud.solicitanteName || "Usuario",
      notas: "Solicitud de mantenci\xF3n creada"
    });
    return newSolicitud;
  }
  async getSolicitudesMantencion(filters) {
    const conditions = [];
    if (filters?.solicitanteId) {
      conditions.push(eq2(solicitudesMantencion.solicitanteId, filters.solicitanteId));
    }
    if (filters?.tecnicoAsignadoId) {
      conditions.push(eq2(solicitudesMantencion.tecnicoAsignadoId, filters.tecnicoAsignadoId));
    }
    if (filters?.estado) {
      conditions.push(eq2(solicitudesMantencion.estado, filters.estado));
    }
    if (filters?.gravedad) {
      conditions.push(eq2(solicitudesMantencion.gravedad, filters.gravedad));
    }
    if (filters?.area) {
      conditions.push(eq2(solicitudesMantencion.area, filters.area));
    }
    let query = db.select().from(solicitudesMantencion).orderBy(desc(solicitudesMantencion.fechaSolicitud));
    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }
    if (filters?.limit) {
      query = query.limit(filters.limit);
    }
    if (filters?.offset) {
      query = query.offset(filters.offset);
    }
    const solicitudes = await query;
    const solicitudesWithDetails = await Promise.all(
      solicitudes.map(async (solicitud) => {
        const [photos, historial, resolucionPhotos] = await Promise.all([
          this.getMantencionPhotos(solicitud.id),
          this.getMantencionHistorial(solicitud.id),
          this.getMantencionResolucionPhotos(solicitud.id)
        ]);
        return {
          ...solicitud,
          photos,
          historial,
          resolucionPhotos
        };
      })
    );
    return solicitudesWithDetails;
  }
  async getSolicitudMantencionById(id) {
    const [solicitud] = await db.select().from(solicitudesMantencion).where(eq2(solicitudesMantencion.id, id));
    return solicitud;
  }
