async function updateETLConfig(etlName, customWatermark, useCustomWatermark, keepCustomWatermark, timeoutMinutes, intervalMinutes) {
  const startTime = Date.now();
  try {
    console.log(`[ETL-CONFIG] Starting config update for ${etlName}`);
    console.log("[ETL-CONFIG] Checking for existing config...");
    const existing = await db.select().from(etlConfig).where(eq5(etlConfig.etlName, etlName)).limit(1);
    console.log(`[ETL-CONFIG] Existing config found: ${existing.length > 0}`);
    if (existing.length > 0) {
      const updateData = { updatedAt: /* @__PURE__ */ new Date() };
      if (customWatermark !== void 0) updateData.customWatermark = customWatermark;
      if (useCustomWatermark !== void 0) updateData.useCustomWatermark = useCustomWatermark;
      if (keepCustomWatermark !== void 0) updateData.keepCustomWatermark = keepCustomWatermark;
      if (timeoutMinutes !== void 0) updateData.timeoutMinutes = timeoutMinutes;
      if (intervalMinutes !== void 0) updateData.intervalMinutes = intervalMinutes;
      console.log("[ETL-CONFIG] Updating existing config with:", updateData);
      const [updated] = await db.update(etlConfig).set(updateData).where(eq5(etlConfig.etlName, etlName)).returning();
      console.log(`[ETL-CONFIG] Config updated successfully in ${Date.now() - startTime}ms`);
      return updated;
    } else {
      const newConfigData = {
        etlName,
        customWatermark: customWatermark || null,
        useCustomWatermark: useCustomWatermark || false,
        timeoutMinutes: timeoutMinutes || 10,
        intervalMinutes: intervalMinutes || 15
      };
      console.log("[ETL-CONFIG] Creating new config with:", newConfigData);
      const [newConfig] = await db.insert(etlConfig).values(newConfigData).returning();
      console.log(`[ETL-CONFIG] Config created successfully in ${Date.now() - startTime}ms`);
      return newConfig;
    }
  } catch (error) {
    const duration = Date.now() - startTime;
    console.error(`[ETL-CONFIG] Error updating ETL config after ${duration}ms:`, {
      etlName,
      errorMessage: error.message,
      errorCode: error.code,
      errorName: error.name,
      errorStack: error.stack,
      customWatermark,
      useCustomWatermark,
      keepCustomWatermark,
      timeoutMinutes,
      intervalMinutes
    });
    const enhancedError = new Error(`Failed to update ETL config for ${etlName}: ${error.message}`);
    enhancedError.stack = error.stack;
    throw enhancedError;
  }
}
async function getETLStatus(etlName = "ventas_incremental", startDate, endDate) {
  try {
    let lastExecutions = [];
    let totalExecutionsResult = [];
    let successfulExecutionsResult = [];
    let failedExecutionsResult = [];
    if (etlName === "nvv") {
      const nvvLogs = await db.execute(sql4`
        SELECT id, start_time as "startTime", end_time as "endTime", status, 
               records_processed as "recordsProcessed", 
               records_inserted as "recordsInserted",
               records_updated as "recordsUpdated",
               status_changes as "statusChanges",
               execution_time_ms as "executionTimeMs",
               error_message as "errorMessage",
               watermark_date as "watermarkDate",
               period, branches
        FROM nvv.nvv_sync_log
        ORDER BY start_time DESC
        LIMIT 100
      `);
      lastExecutions = nvvLogs.rows || [];
      const totalCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM nvv.nvv_sync_log`);
      totalExecutionsResult = [totalCount.rows?.[0] || { count: 0 }];
      const successCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM nvv.nvv_sync_log WHERE status = 'success'`);
      successfulExecutionsResult = [successCount.rows?.[0] || { count: 0 }];
      const failCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM nvv.nvv_sync_log WHERE status IN ('failed', 'error')`);
      failedExecutionsResult = [failCount.rows?.[0] || { count: 0 }];
    } else if (etlName === "gdv") {
      const gdvLogs = await db.execute(sql4`
        SELECT id, start_time as "startTime", end_time as "endTime", status, 
               records_processed as "recordsProcessed",
               records_inserted as "recordsInserted",
               records_updated as "recordsUpdated",
               status_changes as "statusChanges",
               execution_time_ms as "executionTimeMs",
               error_message as "errorMessage",
               watermark_date as "watermarkDate",
               period, branches
        FROM gdv.gdv_sync_log
        ORDER BY start_time DESC
        LIMIT 100
      `);
      lastExecutions = gdvLogs.rows || [];
      const totalCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM gdv.gdv_sync_log`);
      totalExecutionsResult = [totalCount.rows?.[0] || { count: 0 }];
      const successCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM gdv.gdv_sync_log WHERE status = 'success'`);
      successfulExecutionsResult = [successCount.rows?.[0] || { count: 0 }];
      const failCount = await db.execute(sql4`SELECT COUNT(*)::int as count FROM gdv.gdv_sync_log WHERE status IN ('failed', 'error')`);
      failedExecutionsResult = [failCount.rows?.[0] || { count: 0 }];
    } else {
      let whereConditions = eq5(etlExecutionLog.etlName, etlName);
      if (startDate && endDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        whereConditions = sql4`${etlExecutionLog.etlName} = ${etlName} 
          AND ${etlExecutionLog.startTime} >= ${start.toISOString()} 
          AND ${etlExecutionLog.startTime} <= ${end.toISOString()}`;
      }
      lastExecutions = await db.select().from(etlExecutionLog).where(whereConditions).orderBy(desc2(etlExecutionLog.startTime)).limit(100);
      totalExecutionsResult = await db.select({ count: sql4`count(*)::int` }).from(etlExecutionLog).where(eq5(etlExecutionLog.etlName, etlName));
      successfulExecutionsResult = await db.select({ count: sql4`count(*)::int` }).from(etlExecutionLog).where(sql4`etl_name = ${etlName} AND status = 'success'`);
      failedExecutionsResult = await db.select({ count: sql4`count(*)::int` }).from(etlExecutionLog).where(sql4`etl_name = ${etlName} AND (status = 'failed' OR status = 'error')`);
    }
    let totalFactRecordsCount = 0;
    try {
      if (etlName === "nvv") {
        const totalFactResult = await db.execute(sql4`SELECT COUNT(*)::int as count FROM nvv.fact_nvv`);
        totalFactRecordsCount = totalFactResult[0]?.count || 0;
      } else if (etlName === "gdv") {
        const totalFactResult = await db.execute(sql4`SELECT COUNT(*)::int as count FROM gdv.fact_gdv`);
        totalFactRecordsCount = totalFactResult[0]?.count || 0;
      } else {
        const totalFactVentasResult = await db.select({ count: sql4`count(*)::int` }).from(factVentas);
        totalFactRecordsCount = totalFactVentasResult[0]?.count || 0;
      }
    } catch (factTableError) {
      console.warn(`\u26A0\uFE0F  Could not query fact table for ${etlName}:`, factTableError);
    }
    const lastExecution = lastExecutions[0] || null;
    const isRunning = lastExecution?.status === "running";
    const enrichedLastExecution = lastExecution ? {
      ...lastExecution,
      totalFactVentasRecords: totalFactRecordsCount
    } : null;
    const config = await getETLConfig(etlName);
    return {
      lastExecution: enrichedLastExecution,
      isRunning,
      history: lastExecutions,
      totalExecutions: totalExecutionsResult[0]?.count || 0,
      successfulExecutions: successfulExecutionsResult[0]?.count || 0,
      failedExecutions: failedExecutionsResult[0]?.count || 0,
      totalFactVentasRecords: totalFactRecordsCount,
      config
      // Include configuration
    };
  } catch (error) {
    console.error("\u274C Error in getETLStatus:", error);
    return {
      lastExecution: null,
      isRunning: false,
      history: [],
      totalExecutions: 0,
      successfulExecutions: 0,
      failedExecutions: 0,
      totalFactVentasRecords: 0,
      error: error.message
    };
  }
}

