// server/routes.ts
import { format as format2 } from "date-fns";

// server/pdf-to-image.ts
import { createCanvas } from "canvas";
import { exec } from "child_process";
import { promisify } from "util";
import * as fs2 from "fs";
import * as path2 from "path";
import * as os from "os";
var execAsync = promisify(exec);
async function convertWithGhostscript(pdfBuffer, width) {
  const tempDir = os.tmpdir();
  const tempPdfPath = path2.join(tempDir, `pdf_${Date.now()}_${Math.random().toString(36).slice(2)}.pdf`);
  const tempPngPath = path2.join(tempDir, `png_${Date.now()}_${Math.random().toString(36).slice(2)}.png`);
  try {
    fs2.writeFileSync(tempPdfPath, pdfBuffer);
    const dpi = Math.min(150, Math.round(width / 8.5 * 72));
    await execAsync(
      `gs -dSAFER -dBATCH -dNOPAUSE -sDEVICE=png16m -r${dpi} -dFirstPage=1 -dLastPage=1 -sOutputFile="${tempPngPath}" "${tempPdfPath}"`,
      { timeout: 3e4 }
    );
    if (fs2.existsSync(tempPngPath)) {
      const pngBuffer = fs2.readFileSync(tempPngPath);
      console.log(`[PDF-TO-IMAGE] Ghostscript conversion successful: ${pngBuffer.length} bytes`);
      return pngBuffer;
    }
    return null;
  } catch (error) {
    console.error("[PDF-TO-IMAGE] Ghostscript conversion failed:", error);
    return null;
  } finally {
    try {
      if (fs2.existsSync(tempPdfPath)) fs2.unlinkSync(tempPdfPath);
    } catch {
    }
    try {
      if (fs2.existsSync(tempPngPath)) fs2.unlinkSync(tempPngPath);
    } catch {
    }
  }
}
async function convertWithPdfJs(pdfBuffer, width) {
  const pdfjsLib = await import("pdfjs-dist/legacy/build/pdf.mjs");
  const uint8Array = new Uint8Array(pdfBuffer);
  const loadingTask = pdfjsLib.getDocument({
    data: uint8Array,
    useSystemFonts: true,
    disableFontFace: true
  });
  const pdf = await loadingTask.promise;
  const page = await pdf.getPage(1);
  const viewport = page.getViewport({ scale: 1 });
  const scale = width / viewport.width;
  const scaledViewport = page.getViewport({ scale });
  const canvas = createCanvas(scaledViewport.width, scaledViewport.height);
  const context = canvas.getContext("2d");
  const renderContext = {
    canvasContext: context,
    viewport: scaledViewport
  };
  await page.render(renderContext).promise;
  return canvas.toBuffer("image/png");
}
async function convertPdfToImage(pdfBuffer, width = 600) {
  try {
    const result = await convertWithPdfJs(pdfBuffer, width);
    if (result) return result;
  } catch (error) {
    console.log("[PDF-TO-IMAGE] pdf.js failed, trying Ghostscript fallback...");
  }
  try {
    return await convertWithGhostscript(pdfBuffer, width);
  } catch (error) {
    console.error("[PDF-TO-IMAGE] All conversion methods failed:", error);
    return null;
  }
}
function isPdfFile(mimetype, filename) {
  return mimetype === "application/pdf" || filename.toLowerCase().endsWith(".pdf");
}

