async function validateApiKey(req, res, next) {
  const apiKeyHeader = req.headers["x-api-key"];
  if (!apiKeyHeader) {
    return res.status(401).json({
      error: "Unauthorized",
      message: "X-API-Key header is required"
    });
  }
  try {
    const activeKeys = await db.select().from(apiKeys).where(and2(
      eq8(apiKeys.isActive, true)
    ));
    let matchedKey = null;
    for (const key of activeKeys) {
      const isMatch = await bcrypt2.compare(apiKeyHeader, key.keyHash);
      if (isMatch) {
        if (key.expiresAt && new Date(key.expiresAt) < /* @__PURE__ */ new Date()) {
          return res.status(401).json({
            error: "Unauthorized",
            message: "API key has expired"
          });
        }
        matchedKey = key;
        break;
      }
    }
    if (!matchedKey) {
      return res.status(401).json({
        error: "Unauthorized",
        message: "Invalid API key"
      });
    }
    db.update(apiKeys).set({
      lastUsedAt: /* @__PURE__ */ new Date(),
      usageCount: matchedKey.usageCount + 1
    }).where(eq8(apiKeys.id, matchedKey.id)).then(() => {
    }).catch((err) => console.error("Error updating API key usage:", err));
    req.apiKey = {
      id: matchedKey.id,
      role: matchedKey.role,
      name: matchedKey.name
    };
    next();
  } catch (error) {
    console.error("API authentication error:", error);
    return res.status(500).json({
      error: "Internal server error",
      message: "Authentication failed"
    });
  }
}
function requireApiRole(allowedRoles) {
  return (req, res, next) => {
    if (!req.apiKey) {
      return res.status(401).json({
        error: "Unauthorized",
        message: "API key required"
      });
    }
    if (!allowedRoles.includes(req.apiKey.role)) {
      return res.status(403).json({
        error: "Forbidden",
        message: `This endpoint requires one of the following roles: ${allowedRoles.join(", ")}`
      });
    }
    next();
  };
}

