  app2.post("/api/presupuesto-ventas/bulk", requireAdminOrSupervisor, asyncHandler(async (req, res) => {
    try {
      const parsed = bulkPresupuestoVentasSchema.safeParse(req.body);
      if (!parsed.success) {
        return res.status(400).json({
          error: "Datos inv\xE1lidos",
          details: parsed.error.errors
        });
      }
      const { records } = parsed.data;
      let upserted = 0;
      const batchSize = 100;
      for (let i = 0; i < records.length; i += batchSize) {
        const batch = records.slice(i, i + batchSize);
        for (const record of batch) {
          await db.insert(presupuestoVentas).values({
            anio: record.anio,
            mes: record.mes,
            categoria: record.categoria,
            entidad: record.entidad,
            monto: record.monto
          }).onConflictDoUpdate({
            target: [presupuestoVentas.anio, presupuestoVentas.mes, presupuestoVentas.categoria, presupuestoVentas.entidad],
            set: {
              monto: sql7`EXCLUDED.monto`,
              updatedAt: sql7`NOW()`
            }
          });
          upserted++;
        }
      }
      res.json({
        success: true,
        message: `${upserted} registros importados exitosamente`,
        count: upserted
      });
    } catch (error) {
      console.error("[PRESUPUESTO] Bulk import error:", error);
      res.status(500).json({ error: "Error al importar presupuesto: " + error.message });
    }
  }));
