async function uploadLocalImagesToObjectStorage() {
  console.log("\u2601\uFE0F  Verificando im\xE1genes locales para subir a Object Storage...");
  const localImagesDir = path6.join(process.cwd(), "public", "product-images");
  let uploaded = 0;
  let failed = 0;
  let skipped = 0;
  try {
    const migrationCheck = await db.execute(sql9`
      SELECT filename FROM migrations_log WHERE filename = 'local_images_to_object_storage'
    `);
    if (migrationCheck.rows.length > 0) {
      console.log("\u2705 Im\xE1genes ya fueron migradas a Object Storage anteriormente");
      return { uploaded: 0, failed: 0, skipped: 0 };
    }
    if (!fs4.existsSync(localImagesDir)) {
      console.log("\u{1F4C1} No hay directorio de im\xE1genes locales");
      return { uploaded: 0, failed: 0, skipped: 0 };
    }
    const files = fs4.readdirSync(localImagesDir).filter((file) => /\.(jpg|jpeg|png|gif|webp)$/i.test(file));
    if (files.length === 0) {
      console.log("\u{1F4C1} No hay im\xE1genes locales para migrar");
      return { uploaded: 0, failed: 0, skipped: 0 };
    }
    console.log(`\u{1F4F7} Encontradas ${files.length} im\xE1genes locales para subir`);
    const objectStorageService = new ObjectStorageService();
    for (const fileName of files) {
      try {
        const filePath = path6.join(localImagesDir, fileName);
        const imageBuffer = fs4.readFileSync(filePath);
        const ext = path6.extname(fileName).toLowerCase();
        const mimeTypes = {
          ".png": "image/png",
          ".jpg": "image/jpeg",
          ".jpeg": "image/jpeg",
          ".gif": "image/gif",
          ".webp": "image/webp"
        };
        const contentType = mimeTypes[ext] || "image/png";
        await objectStorageService.uploadImage(
          `product-images/${fileName}`,
          imageBuffer,
          contentType
        );
        uploaded++;
        if (uploaded % 50 === 0) {
          console.log(`  \u2601\uFE0F  Subidas ${uploaded}/${files.length} im\xE1genes...`);
        }
      } catch (error) {
        console.warn(`  \u26A0\uFE0F Error subiendo ${fileName}: ${error.message}`);
        failed++;
      }
    }
    if (uploaded > 0) {
      await db.execute(sql9`
        INSERT INTO migrations_log (filename) VALUES ('local_images_to_object_storage')
        ON CONFLICT (filename) DO NOTHING
      `);
    }
    console.log(`\u2705 Migraci\xF3n de im\xE1genes completada: ${uploaded} subidas, ${failed} errores`);
    return { uploaded, failed, skipped };
  } catch (error) {
    console.error("\u274C Error migrando im\xE1genes a Object Storage:", error.message);
    return { uploaded, failed, skipped };
  }
}
async function runProductionMigrations() {
  console.log("\u{1F504} Verificando migraciones de base de datos...");
  try {
    await db.execute(sql9`
      CREATE TABLE IF NOT EXISTS migrations_log (
        id SERIAL PRIMARY KEY,
        filename VARCHAR(255) NOT NULL UNIQUE,
        executed_at TIMESTAMP NOT NULL DEFAULT NOW()
      )
    `);
    const executedMigrations = await db.execute(sql9`
      SELECT filename FROM migrations_log ORDER BY filename
    `);
    const executedSet = new Set(
      executedMigrations.rows.map((row) => row.filename)
    );
    const migrationsDir = path6.join(process.cwd(), "migrations");
    if (!fs4.existsSync(migrationsDir)) {
      console.log("\u26A0\uFE0F  Directorio migrations/ no encontrado");
      return;
    }
    const files = fs4.readdirSync(migrationsDir).filter((f) => f.endsWith(".sql")).filter((f) => !f.startsWith("0000_")).map((f) => ({
      filename: f,
      number: parseInt(f.split("_")[0])
    })).sort((a, b) => a.number - b.number);
    if (files.length === 0) {
      console.log("\u2705 No hay migraciones SQL para ejecutar");
      return;
    }
    let executed = 0;
    for (const migration of files) {
      if (executedSet.has(migration.filename)) {
        continue;
      }
      console.log(`\u{1F4DD} Ejecutando migraci\xF3n: ${migration.filename}`);
      const migrationPath = path6.join(migrationsDir, migration.filename);
      const migrationSQL = fs4.readFileSync(migrationPath, "utf-8");
      try {
        await db.execute(sql9.raw(migrationSQL));
        await db.execute(sql9`
          INSERT INTO migrations_log (filename)
          VALUES (${migration.filename})
        `);
        console.log(`\u2705 Migraci\xF3n completada: ${migration.filename}`);
        executed++;
      } catch (error) {
        console.error(`\u274C Error en migraci\xF3n ${migration.filename}:`, error.message);
        throw error;
      }
    }
    if (executed === 0) {
      console.log("\u2705 Todas las migraciones est\xE1n actualizadas");
    } else {
      console.log(`\u2705 ${executed} migraci\xF3n(es) ejecutada(s) exitosamente`);
    }
  } catch (error) {
    console.error("\u274C Error en sistema de migraciones:", error.message);
    throw error;
  }
}
