async function syncMissingFundMovements() {
  let synced = 0;
  let errors = 0;
  try {
    const rows = await db.execute(sql9`
      SELECT ge.id, ge.monto, ge.estado, ge.descripcion, ge.categoria,
             ge.fund_allocation_id,
             ge.user_id,
             ge.created_at
      FROM gastos_empresariales ge
      INNER JOIN fund_allocations fa ON fa.id = ge.fund_allocation_id
      WHERE ge.fund_allocation_id IS NOT NULL
        AND ge.estado IN ('aprobado', 'rechazado', 'pendiente_rrhh', 'pendiente_supervisor')
        AND NOT EXISTS (
          SELECT 1 FROM fund_movements fm WHERE fm.gasto_id = ge.id
        )
      ORDER BY ge.created_at ASC
    `);
    const expenses = rows.rows;
    if (expenses.length === 0) {
      console.log("\u2705 Todos los movimientos de fondos est\xE1n sincronizados");
      return { synced: 0, errors: 0 };
    }
    console.log(`\u{1F4CA} Encontrados ${expenses.length} gastos con fondo sin movimiento registrado`);
    for (const expense of expenses) {
      try {
        let tipoMovimiento;
        let descripcionMov;
        if (expense.estado === "aprobado") {
          tipoMovimiento = "gasto_aprobado";
          descripcionMov = `Movimiento sincronizado desde gasto hist\xF3rico: ${expense.descripcion || expense.categoria}`;
        } else if (expense.estado === "rechazado") {
          tipoMovimiento = "gasto_rechazado";
          descripcionMov = `Movimiento sincronizado desde gasto hist\xF3rico rechazado: ${expense.descripcion || expense.categoria}`;
        } else {
          tipoMovimiento = "gasto_pendiente";
          descripcionMov = `Movimiento sincronizado desde gasto pendiente: ${expense.descripcion || expense.categoria}`;
        }
        const montoValue = tipoMovimiento === "gasto_rechazado" ? `${Math.abs(parseFloat(expense.monto))}` : `-${Math.abs(parseFloat(expense.monto))}`;
        await db.execute(sql9`
          INSERT INTO fund_movements (id, allocation_id, tipo_movimiento, monto, descripcion, gasto_id, creado_por_id, created_at)
          VALUES (
            gen_random_uuid(),
            ${expense.fund_allocation_id},
            ${tipoMovimiento},
            ${montoValue},
            ${descripcionMov},
            ${expense.id},
            ${expense.user_id},
            ${expense.created_at}
          )
        `);
        synced++;
        console.log(`  \u2705 Sincronizado: ${expense.descripcion || expense.categoria} (${tipoMovimiento})`);
      } catch (err) {
        errors++;
        console.error(`  \u274C Error sincronizando gasto ${expense.id}:`, err.message);
      }
    }
    console.log(`\u{1F4CA} Sincronizaci\xF3n completada: ${synced} sincronizados, ${errors} errores`);
  } catch (error) {
    console.error("\u274C Error en sincronizaci\xF3n de movimientos de fondos:", error.message);
  }
  return { synced, errors };
}

