import { eq as eq10, sql as sql10, and as and4, gte as gte2, lte as lte2, inArray as inArray4 } from "drizzle-orm";
import { toZonedTime, format as formatTZ } from "date-fns-tz";
var CHILE_TIMEZONE = "America/Santiago";
var REPORT_HOUR = 17;
var REPORT_MINUTE = 30;
async function isReportEnabled() {
  try {
    const settings = await db.select().from(emailNotificationSettings).where(eq10(emailNotificationSettings.notificationType, "reporte_diario_ventas"));
    return settings.length > 0 && settings[0].enabled === true;
  } catch (error) {
    console.error("[DAILY-REPORT] Error checking if report is enabled:", error);
    return false;
  }
}
async function getSupervisorsAndAdmins() {
  try {
    const usersWithRoles = await db.select({
      email: users.email
    }).from(users).where(
      and4(
        eq10(users.isActive, true),
        inArray4(users.role, ["admin", "supervisor"])
      )
    );
    return usersWithRoles.map((u) => u.email).filter((email) => email !== null && email.length > 0);
  } catch (error) {
    console.error("[DAILY-REPORT] Error getting supervisors and admins:", error);
    return [];
  }
}
