function getMillisecondsUntilNextReport() {
  const now = toZonedTime(/* @__PURE__ */ new Date(), CHILE_TIMEZONE);
  const targetTime = new Date(now);
  targetTime.setHours(REPORT_HOUR, REPORT_MINUTE, 0, 0);
  if (now >= targetTime) {
    targetTime.setDate(targetTime.getDate() + 1);
  }
  return targetTime.getTime() - now.getTime();
}
function startDailySalesReportScheduler() {
  const msUntilNextReport = getMillisecondsUntilNextReport();
  const hoursUntil = Math.floor(msUntilNextReport / (1e3 * 60 * 60));
  const minutesUntil = Math.floor(msUntilNextReport % (1e3 * 60 * 60) / (1e3 * 60));
  console.log(`[DAILY-REPORT] Scheduler initialized - next report in ${hoursUntil}h ${minutesUntil}m (17:30 Chile time)`);
  setTimeout(() => {
    sendDailySalesReport();
    setInterval(() => {
      sendDailySalesReport();
    }, 24 * 60 * 60 * 1e3);
  }, msUntilNextReport);
}

